import React from "react";
import ApiRequest from "../../Services/ApiRequest";
import FirstTab from "./component/FirstTab";
import SecondTab from "./component/SecondTab";
import ThirdTab from "./component/ThirdTab";
import { Link } from "react-router-dom";
import DLogo from "../../assets/images/DashboardImgs/dashboard-logo.png";
import './postjob.css';


class EditPostJob extends React.Component {

    constructor(props) {
        super(props)
        this.state = {
            step_one: true,
            step_two: false,
            step_three: false,
            postId: '',
            postInfo: [],
            countries: [],
            hiringRoles: [],
            hiringBudget: [],
            languages: [],
        }
        this.handler = this.handler.bind(this)
    }

    componentDidMount() {
        this.setState({
            postId: this.props.match.params.postId
        });

        // get Post Details
        this.getPostData();

        // get Languages
        this.getLanguages();

        // Get Hiring Roles
        this.getHiringRoles();

        // Get Hiring Budgets
        this.getHiringBudget();

        // Get Countries
        this.getCountries();

    }

    getPostData = async () => {
        const response = await ApiRequest.getRequest('/jobPost/' + this.props.match.params.postId)
        if (response && response.status === 200) {
            this.setState({
                postInfo: response.data
            })
        }
    }

    getCountries = async () => {
        const getCountries = await ApiRequest.getRequest('/getCountries');
        if (getCountries && getCountries.data.countries && getCountries.status === 200) {
            this.setState({
                countries: getCountries.data.countries
            })
        }
    }

    getHiringRoles = async () => {
        const getRoles = await ApiRequest.getRequest('/getHiringRoles');
        if (getRoles && getRoles.data.hiringRoles && getRoles.status === 200) {
            this.setState({
                hiringRoles: getRoles.data.hiringRoles
            })
        }
    }

    getHiringBudget = async () => {
        const getbudget = await ApiRequest.getRequest('/getHiringBudget');
        if (getbudget && getbudget.data.hiringBudget && getbudget.status === 200) {
            this.setState({
                hiringBudget: getbudget.data.hiringBudget
            })
        }
    }

    getLanguages = async () => {
        const getlang = await ApiRequest.getRequest('/getLanguages');
        if (getlang && getlang.data.languages && getlang.status === 200) {
            this.setState({
                languages: getlang.data.languages
            })
        }
    }

    // Tab handler
    handler(value, status, response = null) {
        if (status) {
            const btn = ['step_one', 'step_two', 'step_three']
            if (!this.state[`${value}`]) {
                this.setState({
                    [`${value}`]: !this.state[`${value}`]
                })
            }
            btn.map((key) => {
                if (key !== value) {
                    this.setState({
                        [key]: false
                    })
                }
            })
        }
    }

    render() {
        return (
            <div className="container-fluid dashboard-body-bg p-0">
                <div className="row mar-width-0 header-alter">
                    <div className="col-md-12">
                        <Link to="#" className="brand-logo">
                            <img src={DLogo} className="d-logo" alt="" />
                        </Link>
                    </div>
                </div>
                <FirstTab postInfo={this.state.postInfo} languages={this.state.languages} hiringRoles={this.state.hiringRoles} hiringBudget={this.state.hiringBudget} countries={this.state.countries} className={!this.state.step_one ? 'd-none' : ''} handler={this.handler} readOnly={false} />
                <SecondTab  className={!this.state.step_two ? 'd-none' : ''} handler={this.handler} postInfo={this.state.postInfo} readOnly={false}/>
                <ThirdTab  className={!this.state.step_three ? 'd-none' : ''} handler={this.handler} postInfo={this.state.postInfo} readOnly={false}/>
            </div>
        )
    }
}

export default EditPostJob;